def get_xamx():
  print('xmax = {', end='')
  for c in xmax:
    x = round(xmax[c] * 100 / 87.36, 3)
    if c != '^': print(f'\'{c}\': {x}', end=', ')
    else: print(f'\'{c}\': {x}', end='')
  print('}')


def get_chars():
  print('chars = {')
  for t in chars:
    print(f'  \'{t}\': [[', end='')
    for xy in chars[t]:
      for x, y in xy:
        x = round(x * 100 / 87.36, 3)
        y = round(y * 100 / 87.36, 3)
        print(f'({x}, {y})', end=', ')
      print('\b\b], [', end='')
    print('\b\b\b], ')
  print('}')
